const UI_PREFS = {
  theme: "antares_theme_v1",
  publicLang: "antares_public_lang_v1"
};

const HR_WORKSPACE_STORAGE = {
  payroll: "antares_hr_payroll_workspace_v1",
  hiring: "antares_hr_hiring_workspace_v1"
};

const CLIENT_DATA_SCOPE_STORAGE = "antares_client_data_scope_v1";
const CLIENT_DATA_SCOPE = {
  COMPANY: "company",
  INDIVIDUAL: "individual"
};
const HR_VALID_PAYROLL_WS = new Set(["operate", "data"]);
const HR_VALID_HIRING_WS = new Set(["operate", "data"]);

function normalizeHrWorkspace(moduleId, workspace) {
  const ws = String(workspace || "");
  if (ws === "overview") return "operate";
  if (moduleId === "payroll") return HR_VALID_PAYROLL_WS.has(ws) ? ws : "operate";
  if (moduleId === "hiring") {
    if (ws === "track") return "data";
    return HR_VALID_HIRING_WS.has(ws) ? ws : "operate";
  }
  return ws;
}

function hydrateHrWorkspaceFromStorage() {
  try {
    const p = localStorage.getItem(HR_WORKSPACE_STORAGE.payroll);
    const h = localStorage.getItem(HR_WORKSPACE_STORAGE.hiring);
    if (p) {
      const ws = normalizeHrWorkspace("payroll", p);
      state.payrollUi = { ...(state.payrollUi || {}), workspace: ws };
      if (p !== ws) persistHrWorkspace("payroll", ws);
    }
    if (h) {
      let parsed = null;
      try {
        parsed = JSON.parse(h);
      } catch (_jsonErr) {
        parsed = null;
      }
      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
        state.hiringUi = {
          ...(state.hiringUi || {}),
          workspace: normalizeHrWorkspace("hiring", parsed.workspace),
          operateSection: normalizeHiringOperateSection(parsed.operateSection),
          dataSection: normalizeHiringDataSection(parsed.dataSection),
          candidateFilter: String(parsed.candidateFilter || "active"),
          vacancyFilter: String(parsed.vacancyFilter || "open"),
          candidateSort: String(parsed.candidateSort || "recent")
        };
      } else {
        const ws = normalizeHrWorkspace("hiring", h);
        state.hiringUi = { ...(state.hiringUi || {}), workspace: ws };
      }
    }
  } catch (_e) {}
}

function hydrateClientDataScopeFromStorage() {
  try {
    const raw = localStorage.getItem(CLIENT_DATA_SCOPE_STORAGE);
    if (raw === CLIENT_DATA_SCOPE.INDIVIDUAL || raw === CLIENT_DATA_SCOPE.COMPANY) {
      state.clientDataScope = raw;
    }
  } catch (_e) {}
}

function getClientDataScope() {
  const s = String(state.clientDataScope || CLIENT_DATA_SCOPE.COMPANY);
  return s === CLIENT_DATA_SCOPE.INDIVIDUAL ? CLIENT_DATA_SCOPE.INDIVIDUAL : CLIENT_DATA_SCOPE.COMPANY;
}

function persistClientDataScope(scope) {
  const next =
    String(scope || "") === CLIENT_DATA_SCOPE.INDIVIDUAL
      ? CLIENT_DATA_SCOPE.INDIVIDUAL
      : CLIENT_DATA_SCOPE.COMPANY;
  state.clientDataScope = next;
  try {
    localStorage.setItem(CLIENT_DATA_SCOPE_STORAGE, next);
  } catch (_e) {}
}

function isPortalClientUser(user) {
  return user?.role === ROLES.CLIENT;
}

function clientRequestsScopePrimaryLabel() {
  return getClientDataScope() === CLIENT_DATA_SCOPE.INDIVIDUAL
    ? "Mis solicitudes"
    : "Solicitudes de mi empresa";
}

function clientDataScopeBarHtml(activeScope) {
  const active =
    String(activeScope || "") === CLIENT_DATA_SCOPE.INDIVIDUAL
      ? CLIENT_DATA_SCOPE.INDIVIDUAL
      : CLIENT_DATA_SCOPE.COMPANY;
  const pill = (key, label) =>
    `<button type="button" class="ops-filter-pill${active === key ? " is-active" : ""}" data-action="client-data-scope" data-scope="${escapeAttr(key)}"><span>${escapeHtml(label)}</span></button>`;
  return `<div class="client-data-scope-bar ops-filters-bar" role="group" aria-label="Alcance de datos">
    <span class="muted client-data-scope-label">${IC.briefcase} Ver:</span>
    ${pill(CLIENT_DATA_SCOPE.COMPANY, "Toda mi empresa")}
    ${pill(CLIENT_DATA_SCOPE.INDIVIDUAL, "Solo mis solicitudes")}
  </div>`;
}

function persistHrWorkspace(moduleId, workspace) {
  const ws = String(workspace || "");
  try {
    if (moduleId === "payroll" && HR_VALID_PAYROLL_WS.has(ws)) {
      localStorage.setItem(HR_WORKSPACE_STORAGE.payroll, ws);
    } else if (moduleId === "hiring") {
      const ui = { ...(state.hiringUi || {}) };
      if (HR_VALID_HIRING_WS.has(ws)) ui.workspace = ws;
      state.hiringUi = ui;
      localStorage.setItem(
        HR_WORKSPACE_STORAGE.hiring,
        JSON.stringify({
          workspace: normalizeHrWorkspace("hiring", ui.workspace),
          operateSection: normalizeHiringOperateSection(ui.operateSection),
          dataSection: normalizeHiringDataSection(ui.dataSection),
          candidateFilter: String(ui.candidateFilter || "active"),
          vacancyFilter: String(ui.vacancyFilter || "open"),
          candidateSort: String(ui.candidateSort || "recent")
        })
      );
    }
  } catch (_e) {}
}

/** Misma política que modules/core/persistence.js cuando no hay AntaresPersistence. */
function capStoredArrayRows(key, value) {
  const caps = { [KEYS.notifications]: 500, [KEYS.emails]: 400 };
  const max = caps[key];
  if (!max || !Array.isArray(value) || value.length <= max) return value;
  return value.slice(0, max);
}

function read(key, fallback = []) {
  const P = window.AntaresPersistence;
  const normalizeShape = (value) => {
    if (Array.isArray(fallback)) return Array.isArray(value) ? value : fallback;
    if (fallback && typeof fallback === "object") {
      return value && typeof value === "object" && !Array.isArray(value) ? value : fallback;
    }
    return value ?? fallback;
  };
  if (P && typeof P.read === "function") return normalizeShape(P.read(key, fallback));
  try {
    return normalizeShape(JSON.parse(localStorage.getItem(key)));
  } catch (_error) {
    return fallback;
  }
}

function readArray(key) {
  const value = read(key, []);
  return Array.isArray(value) ? value : [];
}

function write(key, value, opts = {}) {
  const skipSyncSchedule = opts?.skipSyncSchedule === true;
  const P = window.AntaresPersistence;
  if (P && typeof P.write === "function") {
    P.write(key, value, opts);
  } else {
    const stored = capStoredArrayRows(key, value);
    localStorage.setItem(key, JSON.stringify(stored));
    if (!skipSyncSchedule && window.AntaresPortalSync && typeof window.AntaresPortalSync.schedule === "function") {
      window.AntaresPortalSync.schedule(key, stored);
    }
  }
  /** Contador de campana lateral: mismo valor que tras F5 ante cualquier mutación local o bootstrap. */
  if (key === KEYS.notifications && getSession()) {
    try {
      updateNotificationBadge();
    } catch (_e) {
      /* DOM aún sin portal o función no inicializada */
    }
  }
}

/**
 * Igual que `write` pero espera POST /portal/sync-key (PostgreSQL) cuando hay sesión API.
 * En modo sólo navegador (sin URL de API/token) sólo persiste la proyección en memoria.
 * @throws Las mismas errores que `AntaresPortalSync.flushStorageKeyNow` cuando el servidor rechaza tras reintentos.
 */
async function writeAwaitServer(storageKeyLike, value, opts = {}) {
  write(storageKeyLike, value, { skipSyncSchedule: true });
  const api = window.AntaresApi;
  const sync = window.AntaresPortalSync;
  if (!sync || typeof sync.flushStorageKeyNow !== "function") return;
  const hasApiBase = api && typeof api.getBase === "function" && Boolean(api.getBase());
  if (!hasApiBase) return;
  const token =
    typeof api.getAccessToken === "function"
      ? String(api.getAccessToken() || "").trim() || String(getSession()?.accessToken || "").trim()
      : "";
  if (!token) {
    throw new Error(
      "Sesión sin token de API. Vuelva a iniciar sesión para guardar en el servidor."
    );
  }
  const flushOpts = { notifyOnFailure: opts.notifyOnFailure !== false };
  if (opts.deletedIds && Array.isArray(opts.deletedIds) && opts.deletedIds.length > 0) {
    flushOpts.deletedIds = opts.deletedIds.map((id) => String(id || "").trim()).filter(Boolean);
  }
  await sync.flushStorageKeyNow(storageKeyLike, flushOpts);
}

/**
 * Persiste una lista podada en PostgreSQL; admite lista vacía vía deletedIds.
 * @returns {Promise<boolean>}
 */
async function writePortalListPrunedAwaitServer(storageKey, nextList, deletedIds = [], opts = {}) {
  const prev = read(storageKey, []);
  const normalizedDeleted = [
    ...new Set(
      (Array.isArray(deletedIds) ? deletedIds : [deletedIds])
        .map((id) => String(id || "").trim())
        .filter(Boolean)
    )
  ];
  try {
    await writeAwaitServer(storageKey, nextList, {
      deletedIds: normalizedDeleted.length ? normalizedDeleted : undefined,
      notifyOnFailure: opts.notifyOnFailure
    });
    return true;
  } catch (err) {
    write(storageKey, prev, { skipSyncSchedule: true });
    if (opts.notifyOnFailure !== false) {
      notify(String(err?.message || "No se pudo guardar el cambio en el servidor."), "error");
    }
    return false;
  }
}

/**
 * Quita una fila del catálogo en memoria y confirma en PostgreSQL (incluye lista vacía).
 * @returns {Promise<boolean>} true si el servidor confirmó (o no hay API).
 */
async function removeFromPortalListAwaitServer(storageKey, rowId, opts = {}) {
  const id = String(rowId || "").trim();
  if (!id) return false;
  const prev = read(storageKey, []);
  if (!Array.isArray(prev)) return false;
  const next = prev.filter((row) => String(row?.id || "") !== id);
  if (next.length === prev.length) return false;
  return writePortalListPrunedAwaitServer(storageKey, next, [id], opts);
}

function decodeJwtPayload(token) {
  try {
    const part = String(token || "").split(".")[1];
    if (!part) return null;
    const json = atob(part.replace(/-/g, "+").replace(/_/g, "/"));
    return JSON.parse(json);
  } catch (_e) {
    return null;
  }
}

function mapJwtRoleToAppRole(roleRaw) {
  const r = String(roleRaw || "client")
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, "_");
  const roleMap = {
    admin: ROLES.ADMIN,
    administrador: ROLES.ADMIN,
    client: ROLES.CLIENT,
    cliente: ROLES.CLIENT,
    rrhh: ROLES.RRHH,
    administracion: ROLES.ADMINISTRACION,
    auxiliar_administrativo: ROLES.AUXILIAR_ADMINISTRATIVO,
    lider_administrativo: ROLES.LIDER_ADMINISTRATIVO,
    logistica: ROLES.LOGISTICA,
    logistics: ROLES.LOGISTICA
  };
  return roleMap[r] || ROLES.CLIENT;
}

/**
 * Tras login API, /portal/bootstrap puede no haber hidratado caché aún; sin fila en KEYS.users el flujo abortaba.
 * Los claims del access token vienen de la misma API (sub, email, role) y permiten abrir sesión hasta el próximo bootstrap.
 */
function upsertPortalUserStubFromJwtPayload(payload) {
  if (!payload || typeof payload !== "object") return null;
  const uid = String(payload.sub || "").trim();
  const email = String(payload.email || "").trim();
  if (!uid || !email) return null;
  const users = read(KEYS.users, []);
  const existing = users.find((u) => String(u.id) === uid);
  if (existing) return existing;
  const localPart = email.split("@")[0] || "";
  const stub = {
    id: uid,
    email,
    name: localPart.replace(/[._-]+/g, " ").trim() || email,
    role: mapJwtRoleToAppRole(payload.role),
    accountStatus: "aprobado",
    companyId: "",
    company: "",
    password: "",
    permissions: [],
    taxId: "",
    phone: ""
  };
  write(KEYS.users, [stub, ...users.filter((u) => String(u.id) !== uid)]);
  return stub;
}

/**
 * Inserta o reemplaza una fila de usuario (formato `loadUsers`) en `KEYS.users`.
 * Usado como fallback ligero si /portal/bootstrap falla pero /portal/me responde:
 * así Mi perfil renderiza con datos reales en vez de stub vacío del JWT.
 */
function upsertPortalUserRowIntoCache(row) {
  if (!row || typeof row !== "object") return null;
  const uid = String(row.id || "").trim();
  if (!uid) return null;
  const normalized = normalizePortalBootstrapUserRow(row);
  const users = read(KEYS.users, []);
  const prev = users.find((u) => String(u.id) === uid);
  const others = users.filter((u) => String(u.id) !== uid);
  const merged = { ...prev, ...normalized };
  write(KEYS.users, [merged, ...others]);
  return merged;
}

/** Mini-identidad persistida en antares_session_v2 para sobrevivir a F5 (caché de usuarios solo en RAM). */
function buildProfileSnapshotFromUserRow(u) {
  if (!u || u.id == null) return null;
  return {
    id: String(u.id),
    email: String(u.email || "").trim(),
    name: String(u.name || "").trim(),
    role: u.role,
    companyId: u.companyId != null ? String(u.companyId) : "",
    permissions: Array.isArray(u.permissions) ? u.permissions : [],
    avatarUrl: String(u.avatarUrl || "").trim()
  };
}

function defaultAdminUsersUi() {
  return {
    panel: "",
    editUserId: "",
    editCompanyId: "",
    section: "pending",
    createUserMinimized: false,
    createCompanyMinimized: false,
    editMinimized: false,
    permissionsMinimized: false
  };
}

function getAdminUsersUi() {
  return { ...defaultAdminUsersUi(), ...(state.adminUsersUi || {}) };
}

function setAdminUsersUi(patch) {
  state.adminUsersUi = { ...getAdminUsersUi(), ...(patch && typeof patch === "object" ? patch : {}) };
}

function getAdminUsersDraft(slot) {
  const key = String(slot || "").trim();
  if (!key) return {};
  const drafts = state.adminUsersDrafts && typeof state.adminUsersDrafts === "object" ? state.adminUsersDrafts : {};
  const raw = drafts[key];
  return raw && typeof raw === "object" ? { ...raw } : {};
}

function setAdminUsersDraft(slot, draft) {
  const key = String(slot || "").trim();
  if (!key) return;
  const next = draft && typeof draft === "object" ? { ...draft } : {};
  state.adminUsersDrafts = {
    ...(state.adminUsersDrafts && typeof state.adminUsersDrafts === "object" ? state.adminUsersDrafts : {}),
    [key]: next
  };
}

function clearAdminUsersDraft(slot) {
  setAdminUsersDraft(slot, {});
}

/** Cuerpo de p-card colapsable (mismo patrón que registro de sesiones en admin). */
function adminUsersCollapsibleCardBody(expanded, toggleAction, panelHtml) {
  return `${renderModulePanelToolbar({ expanded, toggleAction, showWhen: "collapsed" })}
  <div class="${expanded ? "" : "hidden"}" data-admin-collapsible-panel>
    ${panelHtml}
  </div>`;
}

function syncSessionProfileSnapshotFromCache() {
  const s = getSession();
  if (!s?.userId) return;
  const u = read(KEYS.users, []).find((x) => String(x.id) === String(s.userId));
  const snap = buildProfileSnapshotFromUserRow(u);
  if (!snap) return;
  setSession({ ...s, profileSnapshot: snap });
}

/**
 * Tras F5 la tabla users está vacía en RAM hasta el bootstrap; evita clearSession si la sesión en disco sigue siendo válida.
 *
 * Estrategia:
 *  1. `currentUser()` directo (cache repoblado por bootstrap reciente).
 *  2. `profileSnapshot` persistido en la sesión al login (sobrevive a F5).
 *  3. JWT decodificado (claims sub/email/role).
 *  4. Stub mínimo (solo userId + role) — siempre devuelve algo si la sesión está sana.
 *
 * NO bloquea la materialización aunque permisos vengan vacíos: el bootstrap diferido
 * los hidratará cuando la API responda (`__portalRefreshAfterBootstrap` re-evalúa la URL).
 */
function materializePortalUserFromSession(session) {
  if (!session?.userId) return null;
  let user = currentUser();
  if (user && String(user.id) === String(session.userId)) return user;

  const snap = session.profileSnapshot;
  if (snap && String(snap.id) === String(session.userId)) {
    const users = read(KEYS.users, []);
    const prev = users.find((u) => String(u.id) === String(snap.id));
    const row = {
      id: String(snap.id),
      email: String(snap.email || prev?.email || "").trim() || "usuario@portal",
      name: String(snap.name || prev?.name || "").trim() || String(snap.email || "Usuario").trim() || "Usuario",
      role: snap.role || prev?.role || session.role || ROLES.CLIENT,
      accountStatus: prev?.accountStatus || snap.accountStatus || "aprobado",
      companyId: snap.companyId != null ? String(snap.companyId) : String(prev?.companyId || ""),
      company: String(prev?.company || "").trim(),
      password: "",
      permissions: Array.isArray(snap.permissions) ? snap.permissions : prev?.permissions || [],
      avatarUrl: String(snap.avatarUrl || prev?.avatarUrl || "").trim(),
      taxId: portalUserDocumentValue(prev),
      personalDoc: String(prev?.personalDoc || "").trim(),
      phone: String(prev?.phone || "").trim(),
      documentType: String(prev?.documentType || "").trim(),
      birthDate: String(prev?.birthDate || "").trim(),
      createdAt: prev?.createdAt || prev?.registeredAt || "",
      registeredAt: prev?.registeredAt || prev?.createdAt || "",
      systemJoinDate: profileSystemJoinDateValue(prev),
      portalSince: String(prev?.portalSince || "").trim(),
      emergencyContact: String(prev?.emergencyContact || "").trim(),
      emergencyPhone: String(prev?.emergencyPhone || "").trim(),
      emergencyRelation: String(prev?.emergencyRelation || prev?.emergencyRelationship || "").trim(),
      city: String(prev?.city || "").trim(),
      department: String(prev?.department || "").trim()
    };
    write(KEYS.users, [row, ...users.filter((u) => String(u.id) !== String(row.id))]);
    user = currentUser();
    if (user && String(user.id) === String(session.userId)) return user;
  }

  const token = String(session.accessToken || "").trim() || String(window.AntaresApi?.getAccessToken?.() || "").trim();
  if (token) {
    const payload = decodeJwtPayload(token);
    if (payload && String(payload.sub || "").trim() === String(session.userId)) {
      upsertPortalUserStubFromJwtPayload(payload);
    }
    user = currentUser();
    if (user && String(user.id) === String(session.userId)) {
      if (snap && Array.isArray(snap.permissions) && snap.permissions.length && (!user.permissions || !user.permissions.length)) {
        const users = read(KEYS.users, []);
        write(
          KEYS.users,
          users.map((u) =>
            String(u.id) === String(session.userId) ? { ...u, permissions: snap.permissions } : u
          )
        );
        user = currentUser();
      }
      return user;
    }
  }

  /**
   * Fallback final: siempre construimos un stub usable a partir de session.userId. Si falta `role`
   * asumimos cliente para no expulsar al usuario por una sesión incompleta tras F5; cuando el
   * bootstrap responda se rehidrata con el rol real y permisos correctos.
   */
  const fallbackRole = session.role || session.profileSnapshot?.role || ROLES.CLIENT;
  const usersFinal = read(KEYS.users, []);
  const prevFinal = usersFinal.find((u) => String(u.id) === String(session.userId));
  const stubRow = {
    id: String(session.userId),
    email: String(session.profileSnapshot?.email || prevFinal?.email || "").trim() || "usuario@portal",
    name: String(session.profileSnapshot?.name || prevFinal?.name || "").trim() || "Usuario",
    role: fallbackRole,
    accountStatus: prevFinal?.accountStatus || "aprobado",
    companyId: String(session.profileSnapshot?.companyId || prevFinal?.companyId || ""),
    company: String(prevFinal?.company || "").trim(),
    password: "",
    permissions: Array.isArray(session.profileSnapshot?.permissions)
      ? session.profileSnapshot.permissions
      : prevFinal?.permissions || [],
    avatarUrl: String(session.profileSnapshot?.avatarUrl || prevFinal?.avatarUrl || "").trim(),
    taxId: portalUserDocumentValue(prevFinal),
    personalDoc: String(prevFinal?.personalDoc || "").trim(),
    phone: String(prevFinal?.phone || "").trim(),
    documentType: String(prevFinal?.documentType || "").trim(),
    createdAt: prevFinal?.createdAt || prevFinal?.registeredAt || ""
  };
  write(KEYS.users, [stubRow, ...usersFinal.filter((u) => String(u.id) !== String(stubRow.id))]);
  user = currentUser();
  if (user && String(user.id) === String(session.userId)) return user;

  return null;
}

function applyPortalBootstrapPayload(p) {
  if (!p || typeof p !== "object") return;
  const PS = window.AntaresPortalSync;
  if (PS?.beginBootstrap) PS.beginBootstrap();
  try {
    __applyPortalBootstrapPayloadInner(p);
  } finally {
    if (PS?.endBootstrap) PS.endBootstrap();
  }
}

function __applyPortalBootstrapPayloadInner(p) {
  if (p.notificationPreferences !== undefined) {
    applyNotificationPreferencesFromBootstrapPayload(p.notificationPreferences);
  }
  if (p.systemParameters !== undefined) {
    applySystemParametersFromBootstrapPayload(p.systemParameters);
  }
  if (p.systemParametersHistory !== undefined) {
    state.systemParametersHistory = Array.isArray(p.systemParametersHistory) ? p.systemParametersHistory : [];
  }
  if (p.contacts !== undefined) {
    state.portalContacts = Array.isArray(p.contacts) ? p.contacts : [];
  }
  const map = [
    ["users", KEYS.users],
    ["companies", KEYS.companies],
    ["counters", KEYS.counters],
    ["requests", KEYS.requests],
    ["deletedTransportTripLogs", KEYS.deletedTransportTripLogs],
    ["deletedTransportRequestLogs", KEYS.deletedTransportRequestLogs],
    ["vehicles", KEYS.vehicles],
    ["drivers", KEYS.drivers],
    ["notifications", KEYS.notifications],
    ["emails", KEYS.emails],
    ["payrollEmployees", KEYS.payrollEmployees],
    ["payrollRuns", KEYS.payrollRuns],
    ["fuelLogs", KEYS.fuelLogs],
    ["vehicleTechnicalLogs", KEYS.vehicleTechnicalLogs],
    ["travelAllowanceRules", KEYS.travelAllowanceRules],
    ["vacancies", KEYS.vacancies],
    ["candidates", KEYS.candidates],
    ["positions", KEYS.positions],
    ["interviews", KEYS.interviews],
    ["contracts", KEYS.contracts],
    ["hrAbsences", KEYS.hrAbsences],
    ["sstCompliance", KEYS.sstCompliance],
    ["tripRouteRates", KEYS.tripRouteRates],
    ["approvals", KEYS.approvals]
  ];
  for (const [prop, key] of map) {
    if (p[prop] === undefined) continue;
    if (prop === "users") {
      const raw = Array.isArray(p.users) ? p.users : [];
      write(KEYS.users, raw.map(normalizePortalBootstrapUserRow));
      ensureUsersPermissions();
      continue;
    }
    if (prop === "fuelLogs") {
      write(key, normalizeFuelLogsList(Array.isArray(p.fuelLogs) ? p.fuelLogs : []));
      continue;
    }
    if (prop === "vehicleTechnicalLogs") {
      write(key, normalizeVehicleTechnicalLogsList(Array.isArray(p.vehicleTechnicalLogs) ? p.vehicleTechnicalLogs : []));
      continue;
    }
    if (prop === "companies") {
      const raw = Array.isArray(p.companies) ? p.companies : [];
      const prev = read(KEYS.companies, []);
      const prevMap = new Map(prev.map((c) => [String(c.id ?? ""), c]));
      const merged = patchOperatorCompanyKindIfNeeded(
        raw.map((c) => {
          const base = normalizePortalBootstrapCompanyRow(c);
          const row = base && typeof base === "object" ? base : c;
          const id = String(row?.id ?? "");
          const old = id ? prevMap.get(id) : null;
          const explicitInactive =
            row.active === false ||
            String(row.active ?? "").toLowerCase() === "false" ||
            String((row.activeCompany ?? row.companyActive) ?? "").toLowerCase() === "false";
          const active =
            explicitInactive ? false : old && typeof old.active === "boolean" ? old.active : true;
          return { ...row, active };
        })
      );
      write(KEYS.companies, merged);
      continue;
    }
    if (prop === "requests") {
      const raw = Array.isArray(p.requests) ? p.requests : [];
      write(
        KEYS.requests,
        raw.map((row) => {
          if (!row || typeof row !== "object") return row;
          const { attachments: _attachments, ...rest } = row;
          return rest;
        })
      );
      continue;
    }
    if (prop === "notifications") {
      const raw = Array.isArray(p.notifications) ? p.notifications : [];
      const actor = currentUser();
      const filtered =
        actor && !canViewAllNotifications(actor) ? filterNotificationsForUser(actor, raw) : raw;
      const prev = read(KEYS.notifications, []);
      const merged = mergeNotificationsListPreserveReadAt(prev, filtered);
      write(KEYS.notifications, merged);
      continue;
    }
    if (prop === "payrollEmployees") {
      const raw = Array.isArray(p.payrollEmployees) ? p.payrollEmployees : [];
      write(
        KEYS.payrollEmployees,
        raw.map((row) => {
          if (!row || typeof row !== "object") return row;
          const o = { ...row };
          if (!String(o.contractDuration || "").trim() && String(o.contractDurationText || "").trim()) {
            o.contractDuration = String(o.contractDurationText).trim();
          }
          if (!String(o.costCenter || "").trim() && String(o.centro_costos || o.centroCostos || "").trim()) {
            o.costCenter = String(o.centro_costos || o.centroCostos).trim();
          }
          const wr =
            o.workerRole ||
            (String(o.position || "").toLowerCase().includes("conductor") ? "conductor" : "empleado");
          Object.assign(
            o,
            sanitizePayrollEmployeeFieldsForPersist({
              ...o,
              workerRole: wr
            })
          );
          return normalizePayrollEmployeeRowDates(o);
        })
      );
      continue;
    }
    if (prop === "sstCompliance") {
      const raw = Array.isArray(p.sstCompliance) ? p.sstCompliance : [];
      write(KEYS.sstCompliance, raw.map(normalizeSstComplianceRow));
      continue;
    }
    if (prop === "candidates") {
      const raw = Array.isArray(p.candidates) ? p.candidates : [];
      write(
        KEYS.candidates,
        raw.map((row) => {
          if (!row || typeof row !== "object") return row;
          const r = { ...row };
          const st = String(r.status || "").trim();
          const ps = String(r.pipelineStage || "").trim();
          if (!st && ps) r.status = ps;
          if (r.expectedSalary == null && r.salaryExpectation != null)
            r.expectedSalary = Number(r.salaryExpectation) || 0;
          const avail = String(r.availabilityDate || "").trim();
          if (!avail && r.availableFrom != null) {
            const af = r.availableFrom;
            r.availabilityDate = typeof af === "string" ? af.slice(0, 10) : String(af).slice(0, 10);
          }
          if (r.birthDate != null && r.birthDate !== "") {
            r.birthDate = String(r.birthDate).trim().slice(0, 10);
          }
          return r;
        })
      );
      continue;
    }
    if (prop === "positions") {
      const raw = Array.isArray(p.positions) ? p.positions : [];
      const list = raw.map(normalizePortalBootstrapPositionRow).filter(Boolean);
      write(key, list);
      dispatchPositionsCatalogUpdated();
      continue;
    }
    write(key, p[prop]);
  }
}

/** Alinea el token Bearer con la sesión persistida si difieren (evita llamadas silenciosas sin Auth). */
function portalEnsureApiTokensAligned() {
  const api = window.AntaresApi;
  if (!api || typeof api.getAccessToken !== "function" || typeof api.setAccessToken !== "function") return;
  const s = getSession();
  const fromSession = String(s?.accessToken || "").trim();
  if (!fromSession) return;
  const cur = String(api.getAccessToken() || "").trim();
  if (fromSession !== cur) api.setAccessToken(fromSession);
}

/** URL API + JWT (cliente o sesión): mismos criterios que bootstrap tras `portalEnsureApiTokensAligned`. */
function portalCanRefreshFromApi() {
  portalEnsureApiTokensAligned();
  const api = window.AntaresApi;
  if (!api?.getBase?.()) return false;
  const tok =
    String(api.getAccessToken?.() || "").trim() || String(getSession()?.accessToken || "").trim();
  return Boolean(tok);
}

/**
 * POST autenticado al API: usa la misma alineacion JWT↔sesion que bootstrap.
 * Sin URL de backend: no llama al servidor (retorna undefined).
 * Con backend pero sin token/sesión valida: lanza Error (evita borrados solo en caché en produccion).
 */
async function postPortalAuthorized(path, body) {
  const api = window.AntaresApi;
  if (!api?.getBase?.()) return undefined;
  if (!portalCanRefreshFromApi()) {
    throw new Error(
      "No hay sesion valida con el servidor. Revise antares_api_base y vuelva a iniciar sesion."
    );
  }
  return api.postJson(path, body);
}

/**
 * Tras novedades que afectan nómina laboral (ausencias, cambios de salario): crea/actualiza
 * borradores en servidor. Conductores (prestación de servicios) se excluyen — pago por viajes.
 */
async function refreshDriverTripPaymentLinked(employeeId, periodYm, opts = {}) {
  const eid = String(employeeId || "").trim();
  const ym = String(periodYm || "").trim().slice(0, 7);
  if (!eid || !/^\d{4}-\d{2}$/.test(ym) || !portalCanRefreshFromApi()) return null;
  const emp = read(KEYS.payrollEmployees, []).find((e) => String(e.id) === eid);
  if (!emp || !employeeIsConductorServiceProvider(emp)) {
    return { skipped: true, message: "No es conductor en prestación de servicios" };
  }
  try {
    const result = await postPortalAuthorized("/payroll/driver-trip-payment", {
      employeeId: eid,
      periodYm: ym,
      travelAllowanceManualCop: opts.travelAllowanceManualCop,
      fuelReimbursementManualCop: opts.fuelReimbursementManualCop
    });
    if (opts.bootstrap !== false) {
      try {
        await applyPortalBootstrapFromApi();
      } catch (_e) {}
    }
    return result;
  } catch (err) {
    if (opts.notifyOnError !== false) {
      notify(String(err?.message || "No fue posible liquidar los viajes en el servidor."), "warn");
    }
    return null;
  }
}

async function refreshPayrollDraftsLinked(employeeId, startDate, endDate, opts = {}) {
  const eid = String(employeeId || "").trim();
  if (!eid || !portalCanRefreshFromApi()) return null;
  const emp = read(KEYS.payrollEmployees, []).find((e) => String(e.id) === eid);
  if (emp && !employeeReceivesPayrollNomina(emp)) {
    return { created: 0, updated: 0, skipped: 0, conductorTripPay: true };
  }
  try {
    const result = await postPortalAuthorized("/payroll/refresh-drafts", {
      employeeId: eid,
      startDate: startDate ? String(startDate).slice(0, 10) : undefined,
      endDate: endDate ? String(endDate).slice(0, 10) : undefined
    });
    if (opts.bootstrap !== false) {
      try {
        await applyPortalBootstrapFromApi();
      } catch (_e) {}
    }
    return result;
  } catch (err) {
    if (opts.notifyOnError !== false) {
      notify(
        String(err?.message || "La novedad se guardó, pero no se pudo actualizar el borrador de nómina."),
        "warn"
      );
    }
    return null;
  }
}

function payrollDraftLinkSuccessMessage(result, fallback = userMessage("absenceRecorded")) {
  if (result?.conductorTripPay) return userMessage("absenceRecordedConductorTripPay");
  if (!result || typeof result !== "object") return fallback;
  const created = Number(result.created) || 0;
  const updated = Number(result.updated) || 0;
  if (created + updated > 0) {
    const parts = [];
    if (created > 0) parts.push(`${created} borrador${created === 1 ? "" : "es"} creado${created === 1 ? "" : "s"}`);
    if (updated > 0) parts.push(`${updated} liquidación${updated === 1 ? "" : "es"} actualizada${updated === 1 ? "" : "s"}`);
    return `Novedad registrada. Nómina vinculada: ${parts.join(" y ")}.`;
  }
  return fallback;
}

async function applyPortalBootstrapFromApi(opts = {}) {
  if (!portalCanRefreshFromApi()) return false;
  const api = window.AntaresApi;
  /**
   * En refrescos en segundo plano (p. ej. el poll cada 60s) se omiten las llamadas
   * secundarias /portal/positions y /portal/me: rara vez cambian y duplican tráfico.
   * La carga interactiva inicial y los refrescos tras mutaciones las mantienen.
   */
  const skipSecondary = opts.skipSecondaryHydration === true;
  const runBootstrap = async () => {
    const p = await api.getJson("/portal/bootstrap");
    applyPortalBootstrapPayload(p);
    syncSessionProfileSnapshotFromCache();
  };
  /**
   * Si bootstrap falla por completo (p. ej. error 500 en otra tabla), al menos
   * intentamos hidratar el perfil propio para que Mi perfil no quede vacío.
   * Endpoint dedicado: /portal/me (lectura ligera, no depende de tarifas/viajes/etc.).
   */
  const tryHydrateOwnProfileFallback = () => hydrateOwnProfileFromApi();
  try {
    await runBootstrap();
    if (!skipSecondary) {
      await refreshPositionsCatalogFromApi({ rerender: false });
      await hydrateOwnProfileFromApi();
    }
    return true;
  } catch (err) {
    const st = err && typeof err.status === "number" ? err.status : 0;
    if (st === 401) {
      await tryApiRefreshBridge();
      portalEnsureApiTokensAligned();
      if (!portalCanRefreshFromApi()) return false;
      try {
        await runBootstrap();
        await refreshPositionsCatalogFromApi({ rerender: false });
        return true;
      } catch (e2) {
        devWarn("Portal: /portal/bootstrap fallo tras renovar token.", e2?.message || e2);
        await refreshPositionsCatalogFromApi({ rerender: false });
        await tryHydrateOwnProfileFallback();
        return false;
      }
    }
    devWarn("Portal: no se pudo cargar /portal/bootstrap (se usa caché local si existe).", err?.message || err);
    await refreshPositionsCatalogFromApi({ rerender: false });
    await tryHydrateOwnProfileFallback();
    return false;
  }
}

window.refreshPositionsCatalogFromApi = refreshPositionsCatalogFromApi;

/** Fusiona filas de GET /portal/pending-user-registrations sin borrar el resto de usuarios en caché. */
function mergePendingUserRegistrationsIntoCache(rows) {
  if (!Array.isArray(rows)) return;
  const normalized = rows.map(normalizePortalBootstrapUserRow);
  const existing = read(KEYS.users, []);
  const byId = new Map(existing.map((u) => [String(u.id), { ...u }]));
  /** Sólo huérfanos vivos en la respuesta actual: si el admin los borra, deben desaparecer. */
  const orphansSeen = new Set();
  for (const row of normalized) {
    const id = String(row.id || "").trim();
    if (!id) continue;
    const prev = byId.get(id) || {};
    if (pendingUserOrigin(row) === "supabase_auth_only") {
      orphansSeen.add(id);
    }
    byId.set(id, {
      ...prev,
      ...row,
      accountStatus: row.accountStatus || prev.accountStatus || ACCOUNT_STATUS.PENDIENTE,
      source: row.source || prev.source || "portal_db"
    });
  }
  // Remueve huérfanos cacheados que la API ya no devuelve (p.ej. usuario eliminado en Supabase Auth).
  const out = [];
  for (const u of byId.values()) {
    if (pendingUserOrigin(u) === "supabase_auth_only" && !orphansSeen.has(String(u.id))) {
      continue;
    }
    out.push(u);
  }
  write(KEYS.users, out);
}

/** Bandeja de altas pendientes (requiere permiso de autorización de registros web). */
async function applyPendingUserRegistrationsFromApi() {
  if (!portalCanRefreshFromApi()) return false;
  if (!canApprovePortalRegistration(currentUser())) return false;
  const api = window.AntaresApi;
  try {
    const rows = await api.getJson("/portal/pending-user-registrations");
    if (!Array.isArray(rows)) return false;
    mergePendingUserRegistrationsIntoCache(rows);
    return true;
  } catch (err) {
    devWarn("Portal: GET /portal/pending-user-registrations fallo.", err?.message || err);
    return false;
  }
}

/** Lista prospectos B2B sin depender del bootstrap pesado (mitiga fallos al abrir Solicitudes contacto web). */
async function refreshContactB2bProspectsFromApi() {
  if (!portalCanRefreshFromApi()) return false;
  const api = window.AntaresApi;
  try {
    const rows = await api.getJson("/portal/contact-b2b-prospects");
    if (!Array.isArray(rows)) return false;
    state.portalContacts = rows;
    return true;
  } catch (err) {
    devWarn("Portal: GET /portal/contact-b2b-prospects fallo.", err?.message || err);
    return false;
  }
}

/** Solo administración/usuarios: sesiones activas e históricas desde API (tabla sesiones_usuario). */
async function refreshAdminUserSessionsFromApi() {
  if (!portalCanRefreshFromApi()) return false;
  const user = currentUser();
  if (!user || !hasPermission(user, PERMISSIONS.USERS_MANAGE)) return false;
  const api = window.AntaresApi;
  try {
    const rows = await api.getJson("/portal/user-sessions");
    state.adminUserSessions = Array.isArray(rows) ? rows : [];
    state.adminUserSessionsError = null;
    return true;
  } catch (err) {
    state.adminUserSessionsError = String(
      err?.message || "No fue posible consultar sesiones de usuarios en el servidor."
    );
    return false;
  }
}

function adminUsersHasPendingInCache() {
  return read(KEYS.users, []).some((u) => isPortalUserPendingApproval(u));
}

function resolveAdminUsersSectionAfterEntrySync() {
  const ui = getAdminUsersUi();
  const section = normalizeAdminUsersSection(ui.section, adminUsersHasPendingInCache());
  if (section !== ui.section) setAdminUsersUi({ section });
}

let __adminUserSessionsLoadGen = 0;

/**
 * Carga sesiones bajo demanda (pestaña Sesiones o botón Actualizar).
 * Evita un repintado completo del módulo al entrar en Usuarios.
 */
async function ensureAdminUserSessionsLoaded(opts = {}) {
  const force = Boolean(opts && opts.force);
  if (!portalCanRefreshFromApi()) return false;
  if (!hasPermission(currentUser(), PERMISSIONS.USERS_MANAGE)) return false;
  if (state.adminUserSessionsHydrated && !force) return true;
  if (state.adminUserSessionsLoading) return false;
  state.adminUserSessionsLoading = true;
  state.adminUserSessionsError = null;
  const gen = ++__adminUserSessionsLoadGen;
  let ok = false;
  try {
    ok = await refreshAdminUserSessionsFromApi();
  } catch (_e) {
    ok = false;
  } finally {
    if (gen === __adminUserSessionsLoadGen) {
      state.adminUserSessionsLoading = false;
      if (ok) state.adminUserSessionsHydrated = true;
    }
  }
  return ok;
}

/** Pendientes en servidor + bootstrap en curso antes del primer pintado estable del módulo. */
async function syncAdminUsersModuleOnEntry() {
  if (!portalCanRefreshFromApi()) return;
  const tasks = [];
  const boot = window.__portalBootstrapInFlight;
  if (boot && typeof boot.then === "function") tasks.push(boot.catch(() => false));
  if (currentUser()?.role === ROLES.ADMIN) {
    tasks.push(applyPendingUserRegistrationsFromApi().catch(() => false));
  }
  if (tasks.length) await Promise.all(tasks);
}

function finalizeAdminUsersModuleEntry() {
  resolveAdminUsersSectionAfterEntrySync();
  state.adminUsersEntryHydrating = false;
  const ui = getAdminUsersUi();
  if (
    ui.section === "sessions" &&
    portalCanRefreshFromApi() &&
    hasPermission(currentUser(), PERMISSIONS.USERS_MANAGE)
  ) {
    void ensureAdminUserSessionsLoaded().finally(() => {
      if (state.currentView === "admin-users") scheduleRenderPortalView();
    });
    return;
  }
  if (state.currentView === "admin-users") scheduleRenderPortalView();
}

function adminUsersEntryHydratingBodyHtml(activeSection) {
  const active = String(activeSection || "users");
  const panelIds = ["actions", "pending", "users", "companies", "sessions"];
  const panels = panelIds
    .map((id) => {
      const hidden = id !== active ? " hidden" : "";
      const body =
        id === active
          ? `<p class="admin-users-inline-note muted">Actualizando directorio desde el servidor…</p>`
          : "";
      return `<div class="auth-tab-panel${hidden}" data-admin-users-panel="${escapeAttr(id)}"${hidden}>${body}</div>`;
    })
    .join("");
  return `<div class="auth-tab-panels">${panels}</div>`;
}

function adminUsersHydratingShellHtml({ pendingUsers, activeUsers, companies, ui }) {
  const approvedCount = activeUsers.filter((u) => u.accountStatus === ACCOUNT_STATUS.APROBADO).length;
  const activeCompaniesCount = companies.filter((c) => isCompanyRecordActive(c)).length;
  const inactiveCompaniesCount = Math.max(0, companies.length - activeCompaniesCount);
  const section = String(ui.section || "users");
  const sessions = Array.isArray(state.adminUserSessions) ? state.adminUserSessions : [];
  const hero = `<section class="users-hero-strip users-hero-strip--command">
    <div class="admin-users-hero-main">
      <p class="users-hero-kicker">Sistema de acceso y gobierno</p>
      <h2>Usuarios y permisos con una lectura mas clara</h2>
      <p>
        Centralice aprobaciones, altas y cambios de acceso en una vista mas limpia, con menos ruido visual y mejor jerarquia.
      </p>
      <div class="admin-users-hero-chips">
        <span class="status ${pendingUsers.length ? "status-pendiente" : "status-viaje_asignado"}">Pendientes ${pendingUsers.length}</span>
        <span class="status status-viaje_asignado">Aprobados ${approvedCount}</span>
        <span class="status ${inactiveCompaniesCount ? "status-pendiente" : "status-viaje_asignado"}">Empresas activas ${activeCompaniesCount}</span>
      </div>
    </div>
    <div class="admin-users-hero-panel admin-users-hero-panel--compact">
      <p class="admin-users-hero-panel__eyebrow">Acciones rapidas</p>
      <p class="admin-users-hero-panel__copy">
        Abra solo el flujo que necesita y mantenga el resto del modulo despejado.
      </p>
      <div class="users-hero-actions">
        <button class="btn btn-primary btn-sm" data-action="toggle-admin-panel" data-panel="create-user" disabled>${IC.userPlus} Nuevo usuario</button>
        <button class="btn btn-action btn-sm" data-action="toggle-admin-panel" data-panel="create-company" disabled>${IC.building || IC.briefcase} Nueva empresa</button>
        <button class="btn btn-action btn-sm" data-action="toggle-admin-panel" data-panel="set-permissions" disabled>${IC.shield} Asignar permisos</button>
        <button class="btn btn-outline btn-sm" data-action="refresh-user-sessions" disabled>${IC.activity} Actualizar sesiones</button>
      </div>
    </div>
  </section>`;
  const workspaceNav = renderModuleWindowTabs({
    ariaLabel: "Opciones del módulo Usuarios y permisos",
    activeId: section,
    action: "admin-users-section",
    valueAttr: "section",
    tabs: [
      { id: "actions", label: "Acciones" },
      { id: "pending", label: "Pendientes", count: pendingUsers.length },
      { id: "users", label: "Usuarios", count: activeUsers.length },
      { id: "companies", label: "Empresas", count: companies.length },
      { id: "sessions", label: "Sesiones", count: sessions.length }
    ]
  });
  return `${hero}${workspaceNav}${adminUsersEntryHydratingBodyHtml(section)}`;
}

window.applyPortalBootstrapFromApi = applyPortalBootstrapFromApi;
window.portalCanRefreshFromApi = portalCanRefreshFromApi;

async function startPortalBootstrapForInteractiveSession() {
  if (!portalCanRefreshFromApi()) return;
  const p = window.PortalDataLayer?.refreshCacheFromApi
    ? window.PortalDataLayer.refreshCacheFromApi()
    : applyPortalBootstrapFromApi();
  const tracked = Promise.resolve(p);
  window.__portalBootstrapInFlight = tracked.finally(() => {
    if (window.__portalBootstrapInFlight === tracked) window.__portalBootstrapInFlight = null;
  });
  let ok = false;
  try {
    ok = await tracked;
  } catch (_e) {
    /* fallo de red o 401: la vista usa proyección local hasta el próximo intento */
  }
  if (ok && typeof window.__portalRefreshAfterBootstrap === "function") {
    try {
      window.__portalRefreshAfterBootstrap();
    } catch (_e2) {}
  }
}

/** Evita POST /portal/sync-key con el array completo de usuarios mientras se ajusta caché a mano. */
function portalPatchUsersCacheWithoutSyncKey(mutator) {
  if (typeof mutator !== "function") return;
  const PS = window.AntaresPortalSync;
  if (PS?.beginBootstrap) PS.beginBootstrap();
  try {
    mutator();
  } finally {
    if (PS?.endBootstrap) PS.endBootstrap();
  }
}

/**
 * Tras POST que muta usuarios en PostgreSQL: volcado bootstrap y cola de pendientes (admin).
 * El merge de pendientes también va bajo begin/end para no disparar sync-key redundante.
 */
async function portalRefreshBootstrapThenPendingRegistrations() {
  await startPortalBootstrapForInteractiveSession();
  const PS = window.AntaresPortalSync;
  if (PS?.beginBootstrap) PS.beginBootstrap();
  try {
    if (currentUser()?.role === ROLES.ADMIN) {
      await applyPendingUserRegistrationsFromApi();
    }
  } finally {
    if (PS?.endBootstrap) PS.endBootstrap();
  }
}

function reqRead() {
  const rows =
    typeof DomainModules?.requests?.readAllSync === "function"
      ? DomainModules.requests.readAllSync()
      : readArray(KEYS.requests);
  return Array.isArray(rows) ? rows.map(normalizePortalTransportRequestRow) : [];
}

/** Busca solicitud por id (UUID en API, string en DOM `data-id`). */
function findTransportRequestById(id) {
  const key = String(id ?? "").trim();
  if (!key) return null;
  return reqRead().find((r) => String(r.id ?? "").trim() === key) || null;
}

function reqWrite(next) {
  if (typeof DomainModules?.requests?.writeAllSync === "function") {
    DomainModules.requests.writeAllSync(next);
  } else {
    write(KEYS.requests, next);
  }
}

/** Igual que `reqWrite` pero espera `sync-key` con la tabla `solicitudes_transporte` en PostgreSQL. */
async function reqWriteAwait(next) {
  reqWrite(next);
  await writeAwaitServer(KEYS.requests, read(KEYS.requests, []));
}

function normalizePortalTransportRequestRow(row) {
  if (!row || typeof row !== "object") return row;
  const truckType = normalizeRequestRequiredTruckType(row.vehicleType || row.requiredTruckType);
  const siteContactName = String(row.siteContactName ?? row.contactName ?? "").trim();
  const siteContactPhone = String(row.siteContactPhone ?? row.contactPhone ?? "").trim();
  const needsFuelles = requestRequiredTruckTypeShowsFuelles(truckType);
  const normalizedFuelles =
    row.fuelles != null && row.fuelles !== "" ? parseNum(row.fuelles) : needsFuelles ? 0 : row.fuelles ?? null;
  const normalized = {
    ...row,
    vehicleType: truckType || String(row.vehicleType || row.requiredTruckType || "").trim(),
    requiredTruckType: truckType || String(row.requiredTruckType || row.vehicleType || "").trim(),
    fuelles: normalizedFuelles,
    siteContactName,
    siteContactPhone,
    contactName: siteContactName,
    contactPhone: siteContactPhone
  };
  if (normalized.refrigeracionTermoking == null && typeof row.requiresThermoking === "boolean") {
    normalized.refrigeracionTermoking = row.requiresThermoking;
  }
  return normalized;
}

if (typeof window.DomainModules?.requests?.attachStorage === "function") {
  window.DomainModules.requests.attachStorage({ KEYS, read, write });
}
if (typeof window.DomainRegistry?.wireFromAntares === "function") {
  window.DomainRegistry.wireFromAntares({ KEYS, read, write });
}

const publicTextStore = [];
let publicTextCaptured = false;

function capturePublicTextNodes() {
  if (publicTextCaptured) return;
  const scopes = [document.querySelector(".top-nav"), document.getElementById("public-app"), document.querySelector(".site-footer"), document.getElementById("auth-modal")].filter(Boolean);
  scopes.forEach((scope) => {
    const walker = document.createTreeWalker(scope, NodeFilter.SHOW_TEXT);
    let current = walker.nextNode();
    while (current) {
      const original = current.nodeValue;
      if (String(original || "").trim()) {
        publicTextStore.push({ node: current, original });
      }
      current = walker.nextNode();
    }
  });
  publicTextCaptured = true;
}

function normalizePublicKey(value) {
  return String(value || "")
    .replace(/\s+/g, " ")
    .trim()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

function escapePublicRegexFragment(s) {
  return String(s).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

/** Find [start,end) in haystack such that normalizePublicKey(slice) === normalizePublicKey(needle). */
function findNormalizedSpan(haystack, needle) {
  const nNorm = normalizePublicKey(needle);
  if (!nNorm) return null;
  for (let i = 0; i < haystack.length; i++) {
    for (let j = i + 1; j <= haystack.length; j++) {
      const sub = haystack.slice(i, j);
      const subNorm = normalizePublicKey(sub);
      if (subNorm === nNorm) return [i, j];
      if (subNorm.length > nNorm.length) break;
    }
  }
  return null;
}

function replaceAllNormalizedSpans(haystack, needle, replacement) {
  let result = haystack;
  for (let guard = 0; guard < 500; guard++) {
    const span = findNormalizedSpan(result, needle);
    if (!span) break;
    const [a, b] = span;
    result = result.slice(0, a) + replacement + result.slice(b);
  }
  return result;
}

