function initRequiredFieldIndicators() {
  const markerClass = "required-marker";

  const placeMarker = (label) => {
    if (!label || label.querySelector(`.${markerClass}`) || label.querySelector(".field-required-mark")) return;
    const marker = document.createElement("span");
    marker.className = markerClass;
    marker.textContent = "*";
    marker.setAttribute("aria-hidden", "true");

    const labelTextNode = label.querySelector("span");
    if (labelTextNode) {
      labelTextNode.classList.add("required-with-marker");
      labelTextNode.append(" ", marker);
      return;
    }

    label.classList.add("required-with-marker");
    label.append(" ", marker);
  };

  const scanRequiredFields = (root = document) => {
    const requiredFields = root.querySelectorAll("input[required], select[required], textarea[required]");
    requiredFields.forEach((field) => {
      if (field.type === "hidden") return;
      const label = field.closest("label");
      placeMarker(label);
    });
  };

  scanRequiredFields(document);

  const observer = new MutationObserver((mutations) => {
    mutations.forEach((mutation) => {
      mutation.addedNodes.forEach((node) => {
        if (!(node instanceof Element)) return;
        if (node.matches("input[required], select[required], textarea[required]")) {
          const label = node.closest("label");
          placeMarker(label);
        }
        scanRequiredFields(node);
      });
    });
  });

  observer.observe(document.body, { childList: true, subtree: true });
}

/** Carreras públicas: combina GET /api/public/vacancies con vacantes publicadas en este navegador. */
let publicCareersVacanciesSource = "local";
let publicCareersVacanciesFromApi = null;

function normalizeVacancyForCareersPublic(v) {
  if (!v) return null;
  return {
    id: v.id,
    title: String(v.title || ""),
    department: String(v.department || ""),
    city: String(v.city || ""),
    deadline: v.deadline || "",
    publishedFrom: v.publishedFrom || v.visibleFrom || "",
    salaryOffer: parseNum(v.salaryOffer),
    requirements: String(v.requirements || ""),
    status: String(v.status || ""),
    positionName: String(v.positionName || ""),
    modality: String(v.modality || ""),
    openings: v.openings != null ? v.openings : 1,
    workerRole: String(v.workerRole || "")
  };
}

/** Fecha YYYY-MM-DD válida para ventana pública. */
function publicVacancyYmdValid(s) {
  const t = String(s || "").trim();
  if (!t) return false;
  const parts = t.split("-");
  if (parts.length !== 3) return false;
  const cand = new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2])).getTime();
  return Number.isFinite(cand);
}

function publicVacancyYmdToMidnight(s) {
  const parts = String(s || "").trim().split("-");
  return new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2])).getTime();
}

/** Fin de ventana: día de cierre inclusive; al día siguiente ya no se lista. Requiere fecha de cierre. */
function vacancyPublicationDeadlineOk(isoDateStr) {
  const s = String(isoDateStr || "").trim();
  if (!s) return false;
  const parts = s.split("-");
  if (parts.length !== 3) return false;
  const cand = new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2])).getTime();
  if (!Number.isFinite(cand)) return false;
  const t = new Date();
  const t0 = new Date(t.getFullYear(), t.getMonth(), t.getDate()).getTime();
  return cand >= t0;
}

/** Inicio de ventana opcional: si hay fecha, solo se lista cuando el calendario ya llegó a ese día. */
function vacancyPublicationStartOk(isoDateStr) {
  const s = String(isoDateStr || "").trim();
  if (!s) return true;
  const parts = s.split("-");
  if (parts.length !== 3) return false;
  const start = new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2])).getTime();
  if (!Number.isFinite(start)) return false;
  const t = new Date();
  const t0 = new Date(t.getFullYear(), t.getMonth(), t.getDate()).getTime();
  return t0 >= start;
}

function mergeApiVacanciesWithLocalPublished(apiList, localRawList) {
  const out = [];
  const seen = new Set();
  (apiList || []).forEach((row) => {
    const norm = normalizeVacancyForCareersPublic(row);
    if (norm == null || norm.id === undefined || norm.id === null || String(norm.id).trim() === "") return;
    const id = String(norm.id);
    out.push(norm);
    seen.add(id);
  });
  (localRawList || []).forEach((row) => {
    if (String(row?.status || "") !== "Publicada") return;
    const norm = normalizeVacancyForCareersPublic(row);
    if (norm == null || norm.id === undefined || norm.id === null || String(norm.id).trim() === "") return;
    const id = String(norm.id);
    if (seen.has(id)) return;
    out.push(norm);
    seen.add(id);
  });
  return out;
}

function getPublicPublishedVacancies() {
  const rows =
    publicCareersVacanciesSource === "api" && publicCareersVacanciesFromApi !== null && Array.isArray(publicCareersVacanciesFromApi)
      ? publicCareersVacanciesFromApi
      : (read(KEYS.vacancies, []) || []).map((v) => normalizeVacancyForCareersPublic(v)).filter(Boolean);
  return rows.filter(
    (v) =>
      String(v.status || "") === "Publicada" &&
      vacancyPublicationStartOk(v.publishedFrom) &&
      vacancyPublicationDeadlineOk(v.deadline)
  );
}

/** Tras montar el modal de postulación pública: nombre del archivo y botón para quitar y elegir otro. */
function afterMountPublicVacancyAttachmentUi(formEl) {
  const attachInput = formEl?.querySelector?.("input[name='attachment']");
  if (!attachInput) return;
  const label = attachInput.closest("label");
  if (!label) return;
  const bar = document.createElement("div");
  bar.className = "modal-file-attach-actions";
  bar.innerHTML =
    '<span class="muted modal-attach-filename" data-attach-filename title=""></span>' +
    '<button type="button" class="btn btn-sm btn-outline" data-attach-clear hidden>Quitar archivo</button>';
  label.appendChild(bar);
  const nameEl = bar.querySelector("[data-attach-filename]");
  const clearBtn = bar.querySelector("[data-attach-clear]");
  const sync = () => {
    const f = attachInput.files?.[0];
    if (f) {
      nameEl.textContent = f.name;
      nameEl.title = f.name;
      clearBtn.hidden = false;
    } else {
      nameEl.textContent = "";
      nameEl.title = "";
      clearBtn.hidden = true;
    }
  };
  attachInput.addEventListener("change", sync);
  clearBtn.addEventListener("click", () => {
    attachInput.value = "";
    sync();
    try {
      attachInput.focus();
    } catch (_e) {}
  });
}

function openPublicVacancyApplyModal(vacancy) {
  openEditModal({
    title: "Postulacion en linea",
    subtitle: `${vacancy.title} — ${vacancy.positionName || "Vacante Antares"}`,
    submitText: "Enviar candidatura",
    afterMount: afterMountPublicVacancyAttachmentUi,
    fields: [
      { type: "hidden", name: "vacancyId", value: vacancy.id },
      { name: "name", label: "Nombre completo", required: true },
      { name: "email", label: "Correo electronico", type: "email", required: true },
      { name: "phone", label: "Telefono", required: true },
      {
        name: "documentType",
        label: "Tipo de documento",
        type: "select",
        required: true,
        value: "CC",
        options: [
          { value: "CC", label: "Cedula de ciudadania" },
          { value: "CE", label: "Cedula de extranjeria" },
          { value: "PAS", label: "Pasaporte" }
        ]
      },
      { name: "idDoc", label: "Numero de documento", required: true },
      { name: "birthDate", label: "Fecha de nacimiento", type: "date", required: true },
      {
        name: "experienceYears",
        label: "Años de experiencia en el cargo o similar",
        type: "number",
        value: "0",
        min: 0,
        max: 65,
        required: true
      },
      { name: "city", label: "Ciudad de residencia", required: true },
      { name: "address", label: "Direccion", required: true },
      {
        name: "attachment",
        label: "Hoja de vida (PDF, Word o imagen)",
        type: "file",
        accept: ".pdf,.doc,.docx,image/*",
        required: true
      }
    ],
    onSubmit: async (_payload, formEl) => {
      if (!formEl) return false;
      const vac = vacancy;
      if (!vac || vac.status !== "Publicada") {
        notify(userMessage("vacancyPublicClosed"), "error");
        return false;
      }
      const fd = new FormData(formEl);
      const docValidation = validateColombianDocument(String(fd.get("documentType") || ""), String(fd.get("idDoc") || ""));
      if (!docValidation.ok) {
        notify(docValidation.message, "error");
        return false;
      }
      fd.set("idDoc", docValidation.normalized);
      const birth = String(fd.get("birthDate") || "")
        .trim()
        .slice(0, 10);
      const pubAgeInfo = portalCandidateAgeFromBirthIso(birth);
      if (pubAgeInfo.age === null) {
        notify("Indique una fecha de nacimiento válida.", "error");
        return false;
      }
      if (pubAgeInfo.age < 18) {
        notify("Debe tener al menos 18 años para postularse.", "error");
        return false;
      }
      const expY = Math.min(65, Math.max(0, parseNum(String(fd.get("experienceYears") ?? "0"))));
      fd.set("experienceYears", String(expY));
      const attachInput = formEl.querySelector("input[name='attachment']");
      if (!attachInput?.files?.[0]) {
        notify("Adjunte la hoja de vida (PDF, Word o imagen).", "error");
        return false;
      }
      fd.set("email", normalizeEmail(String(fd.get("email") || "")));
      const apiPub = window.AntaresApi;
      if (apiPub?.hasBase?.() && typeof apiPub.postFormDataPublic === "function") {
        try {
          await apiPub.postFormDataPublic("/public/job-application", fd);
          notify(userMessage("candidacySentOk"), "success");
          return true;
        } catch (err) {
          notify(String(err?.message || err), "error");
          return false;
        }
      }
      const vacancyIdFd = String(fd.get("vacancyId") || "");
      const vacLocal = read(KEYS.vacancies, []).find((x) => String(x.id) === vacancyIdFd);
      if (!vacLocal || vacLocal.status !== "Publicada") {
        notify(userMessage("vacancyPublicClosed"), "error");
        return false;
      }
      const cvPieces = await readCandidateHrAttachmentsFromInput(attachInput);
      if (cvPieces === null) return false;
      const nm = String(fd.get("name") || "").trim();
      const all = read(KEYS.candidates, []);
      all.unshift({
        id: newUuidV4(),
        name: normalizeLatinUpperForDb(nm),
        email: normalizeEmail(String(fd.get("email") || "")),
        phone: normalizePortalPhoneForStorage(String(fd.get("phone") || "").trim()),
        documentType: String(fd.get("documentType") || ""),
        idDoc: docValidation.normalized,
        birthDate: birth,
        experienceYears: expY,
        city: normalizeLatinForDb(String(fd.get("city") || "").trim()),
        address: normalizeLatinUpperForDb(String(fd.get("address") || "").trim()),
        vacancyId: vacLocal.id,
        vacancyTitle: vacLocal.title,
        experienceNotes: "",
        expectedSalary: 0,
        availabilityDate: "",
        status: PIPELINE[0],
        attachments: cvPieces,
        source: "Sitio web",
        createdAt: nowIso()
      });
      try {
        await writeAwaitServer(KEYS.candidates, all);
      } catch (err) {
        const raw = String(err?.message || "No fue posible registrar la postulación en el servidor.");
        const msg = /failed to fetch/i.test(raw)
          ? "No fue posible conectar con el servidor para guardar la postulación. Compruebe su conexion y que la API este disponible."
          : raw;
        notify(msg, "error");
        return false;
      }
      sendEmail({
        to: normalizeEmail(String(fd.get("email") || "")),
        subject: "Postulacion recibida - Antares",
        body: `Hola ${nm}, registramos tu postulacion a "${vacLocal.title}". Nuestro equipo de seleccion revisara tu perfil.`
      });
      try {
        await writeAwaitServer(KEYS.emails, read(KEYS.emails, []));
      } catch (_e) {}
      notifyHrUsers(
        "Nueva postulacion (web)",
        `${nm} aplico a "${vacLocal.title}". Revise Contratacion · Pipeline de candidatos.`
      );
      notify(userMessage("candidacySentOk"), "success");
      return true;
    }
  });
}

/** Cobertura pública: GET /api/public/transport-request-coverage-stats (sin JWT). */
let publicCoverageStatsView = null;

/** Rutas principales del index: lista fija (no se sustituye por topHubs de la API). */
const COVERAGE_MAIN_ROUTES_ES = [
  "Santa Marta",
  "Barranquilla",
  "Cartagena",
  "Buenaventura",
  "Puerto Antioquia",
  "Medellin",
  "Oriente Antioqueño",
  "Bogota"
];

function coverageMainRouteHubRows() {
  return COVERAGE_MAIN_ROUTES_ES.map((city) => ({
    city,
    department: null,
    requestCount: null
  }));
}

/** Corredores de referencia (misma forma que topCorridors de la API) para fallback o sin datos. */
const COVERAGE_FALLBACK_CORRIDORS = [
  { cityA: "Santa Marta", cityB: "Barranquilla" },
  { cityA: "Barranquilla", cityB: "Cartagena" },
  { cityA: "Cartagena", cityB: "Buenaventura" },
  { cityA: "Buenaventura", cityB: "Medellin" },
  { cityA: "Medellin", cityB: "Bogota" },
  { cityA: "Oriente Antioqueño", cityB: "Medellin" },
  { cityA: "Medellin", cityB: "Puerto Antioquia" }
];

/** Ventana de meses para GET /public/transport-request-coverage-stats (API acota entre 3 y 36). */
const COVERAGE_STATS_API_MONTHS = 12;

function renderPublicCoverageHubGrid(hubs, showCounts) {
  return hubs
    .map((row) => {
      const city = String(row.city || "").trim();
      if (!city) return "";
      const dept = String(row.department || "").trim();
      const labelHtml = dept
        ? `${escapeHtml(tPublic(city))} (${escapeHtml(dept)})`
        : escapeHtml(tPublic(city));
      const cnt = row.requestCount != null ? Number(row.requestCount) : NaN;
      const badge =
        showCounts && Number.isFinite(cnt)
          ? `<span class="coverage-count" aria-label="${escapeHtml(String(cnt))} solicitudes">${escapeHtml(
              String(cnt)
            )}</span>`
          : "";
      return `<div class="coverage-item"><span class="coverage-dot"></span><span class="coverage-item-label">${labelHtml}</span>${badge}</div>`;
    })
    .filter(Boolean)
    .join("");
}

function renderPublicCoverageCorridorGrid(rows, showCounts) {
  return rows
    .map((row) => {
      const a = String(row.cityA ?? row.originCity ?? "").trim();
      const b = String(row.cityB ?? row.destinationCity ?? "").trim();
      if (!a || !b) return "";
      const deptA = String(row.departmentA ?? row.originDepartment ?? "").trim();
      const deptB = String(row.departmentB ?? row.destinationDepartment ?? "").trim();
      const ta = tPublic(a);
      const tb = tPublic(b);
      const linePlain = `${ta} \u2194 ${tb}`;
      const left = deptA ? `${ta} (${tPublic(deptA)})` : ta;
      const right = deptB ? `${tb} (${tPublic(deptB)})` : tb;
      const title = `${left} \u2194 ${right}`;
      const cnt = row.requestCount != null ? Number(row.requestCount) : NaN;
      const badge =
        showCounts && Number.isFinite(cnt)
          ? `<span class="coverage-count" aria-label="${escapeHtml(String(cnt))} solicitudes">${escapeHtml(
              String(cnt)
            )}</span>`
          : "";
      return `<div class="coverage-item"><span class="coverage-dot"></span><span class="coverage-item-label coverage-corridor-line" title="${escapeHtml(
        title
      )}">${escapeHtml(linePlain)}</span>${badge}</div>`;
    })
    .filter(Boolean)
    .join("");
}

function renderPublicCoverageFromView() {
  const hubGrid = document.getElementById("coverage-hub-grid");
  const corridorGrid = document.getElementById("coverage-corridor-grid");
  const captHub = document.getElementById("coverage-hubs-caption");
  const captCor = document.getElementById("coverage-corridors-caption");
  const foot = document.getElementById("coverage-stats-footnote");
  if (!hubGrid || !corridorGrid) return;

  if (captHub) {
    captHub.textContent = tPublic("Principales puntos de recogida y entrega donde hoy concentramos mas operacion.");
  }
  if (captCor) {
    captCor.textContent = tPublic(
      "Trayectos entre ciudades que mas se repiten; ida y vuelta del mismo corredor se muestran como un solo movimiento."
    );
  }

  const view = publicCoverageStatsView;
  hubGrid.innerHTML = renderPublicCoverageHubGrid(coverageMainRouteHubRows(), false);

  if (!view || view.kind === "fallback") {
    corridorGrid.innerHTML = renderPublicCoverageCorridorGrid(COVERAGE_FALLBACK_CORRIDORS, false);
    if (foot) {
      foot.hidden = false;
      foot.textContent =
        view?.reason === "nobase"
          ? tPublic("Configure la URL del servidor para ver la demanda real en esta seccion.")
          : view?.reason === "empty"
            ? tPublic("No hay solicitudes suficientes en la ventana analizada; se muestra referencia geografica.")
            : view?.reason === "error"
              ? tPublic(
                  "No fue posible cargar las estadisticas de cobertura. Se muestra referencia geografica."
                )
              : tPublic("Configure la URL del servidor para ver la demanda real en esta seccion.");
    }
    return;
  }

  const data = view.data;
  const total = Number(data?.totalRequestsAnalyzed) || 0;
  const topCorridors = Array.isArray(data?.topCorridors) ? data.topCorridors : [];

  const corOk = topCorridors.length > 0;

  corridorGrid.innerHTML = corOk
    ? renderPublicCoverageCorridorGrid(topCorridors, true)
    : renderPublicCoverageCorridorGrid(COVERAGE_FALLBACK_CORRIDORS, false);

  if (foot) {
    if (total > 0 && corOk) {
      foot.hidden = true;
      foot.textContent = "";
    } else {
      foot.hidden = false;
      foot.textContent = tPublic(
        "No hay solicitudes suficientes en la ventana analizada; se muestra referencia geografica."
      );
    }
  }
}

function initCoverageCorridors() {
  const hubGrid = document.getElementById("coverage-hub-grid");
  if (!hubGrid) return;

  if (publicCoverageStatsView) {
    renderPublicCoverageFromView();
    return;
  }

  const api = window.AntaresApi;
  if (!api?.hasBase?.() || typeof api.getJsonPublic !== "function") {
    publicCoverageStatsView = { kind: "fallback", reason: "nobase" };
    renderPublicCoverageFromView();
    return;
  }

  hubGrid.innerHTML = `<div class="coverage-item coverage-item-loading"><span class="coverage-dot"></span><span class="coverage-item-label">${escapeHtml(
    tPublic("Cargando datos de cobertura...")
  )}</span></div>`;
  const corridorGrid = document.getElementById("coverage-corridor-grid");
  if (corridorGrid) {
    corridorGrid.innerHTML = hubGrid.innerHTML;
  }

  void api
    .getJsonPublic(`/public/transport-request-coverage-stats?months=${COVERAGE_STATS_API_MONTHS}`)
    .then((data) => {
      const total = Number(data?.totalRequestsAnalyzed) || 0;
      const topHubs = Array.isArray(data?.topHubs) ? data.topHubs : [];
      const topCorridors = Array.isArray(data?.topCorridors) ? data.topCorridors : [];
      if (total === 0 && !topHubs.length && !topCorridors.length) {
        publicCoverageStatsView = { kind: "fallback", reason: "empty" };
      } else {
        publicCoverageStatsView = { kind: "api", data };
      }
    })
    .catch((err) => {
      devWarn("Cobertura: error al cargar estadisticas desde la API.", err?.message || err);
      publicCoverageStatsView = { kind: "fallback", reason: "error" };
    })
    .finally(() => {
      renderPublicCoverageFromView();
    });
}

function initPublicCareers() {
  const grid = document.getElementById("careers-vacancies-grid");
  if (!grid) return;
  const render = () => {
    const list = getPublicPublishedVacancies();
    if (!list.length) {
      grid.innerHTML =
        `<div class="careers-card"><p class="muted" style="margin:0">${tPublic("No hay vacantes publicadas en este momento. Vuelve pronto o escribenos en Contacto.")}</p></div>`;
      return;
    }
    grid.innerHTML = list
      .map((v) => {
        const salary = parseNum(v.salaryOffer);
        const salaryStr = `$${salary.toLocaleString("es-CO")}`;
        const deadline = v.deadline ? `${tPublic("Cierre")}: ${v.deadline}` : tPublic("Sin fecha limite");
        const req = String(v.requirements || "").slice(0, 180);
        const more = String(v.requirements || "").length > 180 ? "…" : "";
        return `<article class="careers-card lift-card">
          <h3>${v.title}</h3>
          <div class="careers-meta">${v.positionName || tPublic("Cargo")} · ${salaryStr} · ${deadline}</div>
          <p class="careers-req muted">${req}${more}</p>
          <button type="button" class="btn btn-primary full" data-careers-apply data-id="${v.id}">${tPublic("Aplicar")}</button>
        </article>`;
      })
      .join("");
    grid.querySelectorAll("[data-careers-apply]").forEach((btn) => {
      btn.addEventListener("click", () => {
        const vac = getPublicPublishedVacancies().find((x) => x.id === btn.dataset.id);
        if (vac) openPublicVacancyApplyModal(vac);
      });
    });
  };

  const api = window.AntaresApi;
  if (api?.hasBase?.()) {
    publicCareersVacanciesSource = "api";
    publicCareersVacanciesFromApi = null;
    grid.innerHTML =
      `<div class="careers-card"><p class="muted" style="margin:0">${state.publicLang === "en" ? "Loading openings…" : "Cargando vacantes…"}</p></div>`;
    void api
      .getJsonPublic("/public/vacancies")
      .then((rows) => {
        const mapped = Array.isArray(rows)
          ? rows.map((row) => ({
              id: row.id,
              title: row.title,
              department: row.department,
              city: row.city,
              deadline: row.deadline,
              publishedFrom: row.publishedFrom || row.visibleFrom || "",
              salaryOffer: row.salaryOffer,
              requirements: row.requirements,
              status: row.status || "Publicada",
              positionName: row.positionName,
              modality: row.modality,
              openings: row.openings,
              workerRole: row.workerRole
            }))
          : [];
        publicCareersVacanciesFromApi = mergeApiVacanciesWithLocalPublished(mapped, read(KEYS.vacancies, []));
      })
      .catch((err) => {
        devWarn("Carreras: error al cargar vacantes desde la API.", err?.message || err);
        publicCareersVacanciesSource = "local";
        publicCareersVacanciesFromApi = null;
      })
      .finally(() => {
        render();
      });
    return;
  }

  publicCareersVacanciesSource = "local";
  publicCareersVacanciesFromApi = null;
  render();
}

function initPublicScrollSpy() {
  const mainNav = document.getElementById("main-nav");
  if (!mainNav) return;
  const links = [...mainNav.querySelectorAll("a[href^='#']")];
  if (!links.length) return;

  const sectionIds = links
    .map((link) => String(link.getAttribute("href") || "").replace("#", "").trim())
    .filter(Boolean);
  const sections = sectionIds
    .map((id) => document.getElementById(id))
    .filter(Boolean);
  if (!sections.length) return;

  const setActive = (id) => {
    links.forEach((link) => {
      const targetId = String(link.getAttribute("href") || "").replace("#", "").trim();
      link.classList.toggle("active", targetId === id);
    });
  };

  const visibleRatioById = new Map();
  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        const id = entry.target.id;
        visibleRatioById.set(id, entry.isIntersecting ? entry.intersectionRatio : 0);
      });
      const best = [...visibleRatioById.entries()].sort((a, b) => b[1] - a[1])[0];
      if (best && best[1] > 0) setActive(best[0]);
    },
    { threshold: [0.2, 0.35, 0.5, 0.7], rootMargin: "-18% 0px -55% 0px" }
  );

  sections.forEach((section) => {
    visibleRatioById.set(section.id, 0);
    observer.observe(section);
  });

  links.forEach((link) => {
    link.addEventListener("click", () => {
      const targetId = String(link.getAttribute("href") || "").replace("#", "").trim();
      if (targetId) setActive(targetId);
    });
  });

  setActive(sectionIds[0]);
}

function initPublicEffects() {
  if (window.AntaresValidation?.installLiveValidation) {
    window.AntaresValidation.installLiveValidation(document);
  }
  initCoverageCorridors();
  initPublicCareers();
  initPublicScrollSpy();

  const revealItems = document.querySelectorAll("[data-reveal]");
  if (!revealItems.length) return;

  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (!entry.isIntersecting) return;
        entry.target.classList.add("is-visible");
        observer.unobserve(entry.target);
      });
    },
    { threshold: 0.12, rootMargin: "0px 0px -8% 0px" }
  );

  revealItems.forEach((item, index) => {
    item.style.transitionDelay = `${Math.min(index * 40, 280)}ms`;
    observer.observe(item);
  });

  const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  const hero = document.getElementById("hero");
  if (!hero || prefersReducedMotion) return;

  window.addEventListener(
    "scroll",
    () => {
      const offset = window.scrollY * 0.15;
      hero.style.backgroundPosition = `center calc(50% + ${offset}px)`;
    },
    { passive: true }
  );

  const tiltCards = document.querySelectorAll("[data-tilt]");
  tiltCards.forEach((card) => {
    card.addEventListener("mousemove", (event) => {
      const bounds = card.getBoundingClientRect();
      const x = event.clientX - bounds.left;
      const y = event.clientY - bounds.top;
      const rotateY = ((x / bounds.width) - 0.5) * 7;
      const rotateX = (0.5 - y / bounds.height) * 7;
      card.style.transform = `perspective(900px) rotateX(${rotateX.toFixed(2)}deg) rotateY(${rotateY.toFixed(2)}deg) translateY(-6px)`;
    });
    card.addEventListener("mouseleave", () => {
      card.style.transform = "";
    });
  });

}

